import{_ as t,o as a,c as s,a2 as o}from"./chunks/framework.CKCxdkvf.js";const h=JSON.parse('{"title":"RFC-008 — Outer planets + dwarf planets in /plan","description":"","frontmatter":{},"headers":[],"relativePath":"rfc/RFC-008.md","filePath":"rfc/RFC-008.md"}'),r={name:"rfc/RFC-008.md"};function i(n,e,l,c,d,u){return a(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="rfc-008-—-outer-planets-dwarf-planets-in-plan" tabindex="-1">RFC-008 — Outer planets + dwarf planets in /plan <a class="header-anchor" href="#rfc-008-—-outer-planets-dwarf-planets-in-plan" aria-label="Permalink to &quot;RFC-008 — Outer planets + dwarf planets in /plan&quot;">​</a></h1><blockquote><p>Status · Decided · closed by ADR-028 (2026-05-02) Date · 2026-05-02 TA anchor · §components/lambert-worker · §components/plan-screen Related PRDs · PRD-002 (Mission Configurator) Related UXSs · UXS-002 (Mission Configurator) Related ADRs · ADR-008 (Lambert worker), ADR-022 (Lambert protocol), ADR-023 (mobile magnifier), ADR-026 (multi-destination v0.1.6 / 5 destinations), ADR-028 (this RFC&#39;s closure) Why this is an RFC · v0.1.6 (ADR-026) shipped 5 destinations: Mercury, Venus, Mars, Jupiter, Saturn. Three planets and several dwarfs were explicitly deferred to v0.3.0. Adding them isn&#39;t trivial: Uranus&#39;s Hohmann transfer takes ~16 years, Neptune ~30. Pluto&#39;s eccentricity (e=0.249) breaks the circular-orbit approximation we use elsewhere. And every outer-planet mission realistically uses a gravity-assist trajectory, which we don&#39;t model. This RFC asks: what scope, what scaling, what teaching frame.</p></blockquote><h2 id="the-question" tabindex="-1">The question <a class="header-anchor" href="#the-question" aria-label="Permalink to &quot;The question&quot;">​</a></h2><p>The user feedback after v0.1.6: &quot;we should also support outer planets and Pluto.&quot; Implementation has three open questions, each with multiple defensible options:</p><ol><li><strong>Y-axis scaling</strong> for transit times that span 5–35 years.</li><li><strong>Whether to model gravity-assist trajectories</strong>, which dominated every real outer-planet mission.</li><li><strong>Which dwarf planets, if any</strong>, to include — and how to handle Pluto&#39;s eccentric orbit.</li></ol><h2 id="use-cases" tabindex="-1">Use cases <a class="header-anchor" href="#use-cases" aria-label="Permalink to &quot;Use cases&quot;">​</a></h2><ul><li><strong>STEM student</strong> opens /plan, picks Neptune, sees a porkchop with Y-axis spanning ~30 years and discovers viscerally that &quot;Voyager 2 took 12 years&quot; only because of the Jupiter gravity assist — direct Hohmann is much longer.</li><li><strong>Curious learner</strong> picks Pluto, sees no convergent Hohmann transfer in our 0–4 year departure window: the launch windows are decades apart. The plot teaches &quot;this is why New Horizons existed at all.&quot;</li><li><strong>Teacher</strong> uses Uranus + Neptune as the educational outliers — students who internalise Mercury&#39;s ∆v cliff (v0.1.6) and Saturn&#39;s 12-year cycle now confront the fact that there are still planets we&#39;ve barely visited.</li><li><strong>Contributor</strong> asks: &quot;where are the dwarfs?&quot; — RFC-008 settles whether Ceres / Eris / Makemake / Haumea ship.</li></ul><h2 id="goals" tabindex="-1">Goals <a class="header-anchor" href="#goals" aria-label="Permalink to &quot;Goals&quot;">​</a></h2><ul><li>Each new destination gets its own pre-computed porkchop grid (per ADR-026&#39;s pattern).</li><li>Outer-planet transfer times legible at 112 × 100 grid resolution (preserve ADR-023 magnifier contract).</li><li>Honest about gravity-assist: the porkchop shows direct trajectories only; gravity-assist as a separate teaching layer if at all.</li><li>No regression for v0.1.6&#39;s 5 destinations.</li></ul><h2 id="constraints" tabindex="-1">Constraints <a class="header-anchor" href="#constraints" aria-label="Permalink to &quot;Constraints&quot;">​</a></h2><ul><li><strong>ADR-008 + ADR-026</strong> lock the Lambert solver + pre-computed grid pattern. New destinations follow.</li><li><strong>ADR-023</strong> locks the 112 × 100 grid resolution for the mobile magnifier. Transfer-time ranges must scale rather than the grid.</li><li><strong>Lambert convergence</strong> at extreme distances (Pluto perihelion ~30 AU; aphelion ~49 AU) is numerically tricky — Lambert&#39;s iterative solution can diverge for very-high-energy or grazing transfers.</li><li><strong>Build-time data budget</strong> — v0.1.6&#39;s 5 grids were ~110 KB each (~550 KB total). Adding 3 planets + 4 dwarfs = 7 more grids ~770 KB. Acceptable per ADR-016 budget but worth noting.</li><li><strong>Eccentricity</strong> — every other destination uses a circular-orbit approximation (<code>a</code> only). Pluto&#39;s e=0.249 makes that insufficient; either accept the simplification (label &quot;Pluto&#39;s perihelion-only fly-by&quot;), or add e + L0 to the destination model.</li></ul><h2 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to &quot;Options&quot;">​</a></h2><h3 id="y-axis-scaling-transfer-times-span-5–35-years" tabindex="-1">Y-axis scaling (transfer times span 5–35 years) <a class="header-anchor" href="#y-axis-scaling-transfer-times-span-5–35-years" aria-label="Permalink to &quot;Y-axis scaling (transfer times span 5–35 years)&quot;">​</a></h3><p><strong>Option YA-A — Per-destination range with year ticks.</strong> Same as v0.1.6&#39;s two-tier (days for inner, years for outer). Tof for Uranus: [3000, 6500] days = ~8–18 years. Tof for Neptune: [10000, 20000] days = ~27–55 years. The plot reads as &quot;wide&quot; but legible.</p><p><strong>Option YA-B — Logarithmic Y-axis.</strong> A log-scale TOF axis would compress the multi-decade range and let Mars + Neptune display side-by-side in comparison views. Educational moment compromised: porkchops are about <em>cheapness vs date</em>, not <em>cheapness vs log(date)</em>. Users would have to learn the log axis before reading the plot.</p><p><strong>Option YA-C — Drop multi-year missions; show only &quot;fast&quot; trajectories.</strong> Uranus in 8–10 years, Neptune in 12–15 years — these are gravity-assist trajectories. Can&#39;t show direct-Hohmann at all because they&#39;re too long for the user to plan around. Educational frame: &quot;this is why we use Jupiter gravity assists.&quot;</p><h3 id="gravity-assist-modelling" tabindex="-1">Gravity-assist modelling <a class="header-anchor" href="#gravity-assist-modelling" aria-label="Permalink to &quot;Gravity-assist modelling&quot;">​</a></h3><p><strong>Option GA-A — No gravity-assist.</strong> Pre-computed porkchops show direct-Hohmann only. Honest about the limitation: a small footnote on outer-planet panels says &quot;real missions use planetary gravity assists; this view shows direct trajectories only.&quot; Cleanest scope.</p><p><strong>Option GA-B — Two grids per outer destination: direct + Jupiter-assisted.</strong> Toggle on /plan switches between them. Doubles data + Lambert work. The Jupiter-assist grid would require multi-leg Lambert (still solvable but materially more complex math).</p><p><strong>Option GA-C — A &quot;VEEGA / Voyager-style&quot; preset for each destination.</strong> Hardcoded gravity-assist trajectories from real missions (Voyager 2, Galileo, Cassini, New Horizons) shown as reference points overlaid on the direct-Hohmann porkchop. Educational power; engineering scope manageable; doesn&#39;t require a generalised gravity-assist solver.</p><h3 id="dwarf-planets" tabindex="-1">Dwarf planets <a class="header-anchor" href="#dwarf-planets" aria-label="Permalink to &quot;Dwarf planets&quot;">​</a></h3><p><strong>Option DW-A — Skip dwarfs entirely.</strong> Stay at 3 outer planets (Uranus, Neptune, Pluto). Pluto already a dwarf-planet edge case but is the only one with a flown mission (New Horizons) so users expect it.</p><p><strong>Option DW-B — Add Ceres + Pluto only.</strong> Ceres because Dawn flew there (2015 orbit insertion); the asteroid-belt context matters. Pluto because of New Horizons. Skip Eris/Makemake/Haumea — no flown missions, very long transfers.</p><p><strong>Option DW-C — All four dwarf planets</strong> plus Pluto. Educational completeness; data scope grows but is tractable. Eris&#39;s e=0.43 and 558-year orbit make even direct trajectories impractical to plot legibly.</p><h2 id="open-questions-resolved" tabindex="-1">Open questions resolved <a class="header-anchor" href="#open-questions-resolved" aria-label="Permalink to &quot;Open questions resolved&quot;">​</a></h2><ol><li><strong>OQ #1 — Pluto&#39;s eccentricity.</strong> RESOLVED: extend <code>DestinationConstants</code> with optional <code>e</code> field. Pluto uses it; everyone else inherits the v0.1.6 circular approximation. Backward-compat preserved.</li><li><strong>OQ #2 — Lambert convergence at multi-decade transfers.</strong> RESOLVED: add a per-destination convergence-tolerance fallback. Cells that fail to converge render as <code>DV_FAILED</code> (already the convention). Document expected failure rate per destination in the JSON&#39;s <code>credit</code> field.</li><li><strong>OQ #3 — UI affordance for &quot;this trip is decades long&quot;.</strong> RESOLVED: outer-planet panels surface a one-line caveat banner &quot;Direct trajectory shown — real missions use gravity assists&quot; matching the v0.1.7 sparse-data caveat pattern.</li><li><strong>OQ #4 — Should /fly support outer-planet trajectories?</strong> RESOLVED: yes, but with a simplified arc (single half-ellipse, no gravity-assist visualisation). The arc reads &quot;long curve&quot; rather than the real trajectory.</li><li><strong>OQ #5 — Dwarf inclusion timing.</strong> RESOLVED: Pluto + Ceres in v0.3.0. Eris / Makemake / Haumea deferred to a possible v0.4 if user demand emerges; their orbits don&#39;t read well on the porkchop format.</li></ol><h2 id="goals-for-the-closure-adr-adr-028" tabindex="-1">Goals for the closure ADR (ADR-028) <a class="header-anchor" href="#goals-for-the-closure-adr-adr-028" aria-label="Permalink to &quot;Goals for the closure ADR (ADR-028)&quot;">​</a></h2><p>The ADR locks:</p><ul><li>Final destination list for v0.3.0 (Uranus, Neptune, Pluto, Ceres = 4 new entries; total now 9 destinations)</li><li>Y-axis scaling rule (Option YA-A — per-destination range with year ticks)</li><li>Gravity-assist scope (Option GA-A — direct-trajectory only with caveat banner; Option GA-C reference trajectories deferred to v0.4)</li><li>Schema additions to <code>DestinationConstants</code> (optional <code>e</code> field for Pluto)</li><li>Pre-computed grid contract reuse from ADR-026 (no new schema; per-destination JSON files)</li><li>/fly arc geometry handling for multi-year trajectories (single ellipse + caveat)</li><li>Mission-data implications: do existing missions (Voyager 2 to Uranus + Neptune; Dawn to Ceres; New Horizons to Pluto) get added to the catalog? — yes, in scope for v0.3.0.</li></ul>',29)])])}const g=t(r,[["render",i]]);export{h as __pageData,g as default};
